using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;
using ShipmentTracker.Data.Entities;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("/api/shipments").RequireAuthorization();

        // Dispatchers: get all shipments
        group.MapGet("/", async (ApplicationDbContext db) =>
        {
            var shipments = await db.Shipments
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = (Client.Models.ShipmentStatus)(int)s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.CustomerEmail,
                    Description = s.Description
                })
                .ToListAsync();

            return Results.Ok(shipments);
        }).RequireAuthorization("Dispatcher");

        // Dispatchers: update shipment status
        group.MapPut("/status", async (UpdateShipmentStatusRequest request, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(request.ShipmentId);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = (Data.Entities.ShipmentStatus)(int)request.NewStatus;
            await db.SaveChangesAsync();
            return Results.Ok();
        }).RequireAuthorization("Dispatcher");

        // Customers: track by tracking number (public-ish, just needs auth)
        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments
                .Where(s => s.TrackingNumber == trackingNumber)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = (Client.Models.ShipmentStatus)(int)s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.CustomerEmail,
                    Description = s.Description
                })
                .FirstOrDefaultAsync();

            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        });

        // Customers: get my shipments (by email claim)
        group.MapGet("/my", async (HttpContext context, ApplicationDbContext db) =>
        {
            var email = context.User.FindFirst(System.Security.Claims.ClaimTypes.Email)?.Value
                     ?? context.User.FindFirst("email")?.Value
                     ?? context.User.Identity?.Name;

            if (string.IsNullOrEmpty(email))
                return Results.Unauthorized();

            var shipments = await db.Shipments
                .Where(s => s.CustomerEmail == email)
                .OrderByDescending(s => s.ShippedDate)
                .Select(s => new ShipmentDto
                {
                    Id = s.Id,
                    TrackingNumber = s.TrackingNumber,
                    Origin = s.Origin,
                    Destination = s.Destination,
                    Status = (Client.Models.ShipmentStatus)(int)s.Status,
                    ShippedDate = s.ShippedDate,
                    EstimatedDelivery = s.EstimatedDelivery,
                    CustomerEmail = s.CustomerEmail,
                    Description = s.Description
                })
                .ToListAsync();

            return Results.Ok(shipments);
        });
    }
}

