@page "/dispatcher"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Dispatcher")]
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else if (!shipments.Any())
{
    <p>No shipments found.</p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by tracking #, destination, or status..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th @onclick='() => SortBy("tracking")' style="cursor:pointer">Tracking # ↕</th>
                <th @onclick='() => SortBy("destination")' style="cursor:pointer">Destination ↕</th>
                <th @onclick='() => SortBy("status")' style="cursor:pointer">Status ↕</th>
                <th>Origin</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">
                            @shipment.Status
                        </span>
                    </td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                value="@((int)shipment.Status)"
                                @onchange="(e) => UpdateStatus(shipment, e)">
                            @foreach (ShipmentStatus status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@((int)status)">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@if (!string.IsNullOrEmpty(statusMessage))
{
    <div class="alert @(isError ? "alert-danger" : "alert-success") mt-3" role="alert">
        @statusMessage
    </div>
}

@code {
    private List<ShipmentDto>? shipments;
    private string filterText = string.Empty;
    private string sortColumn = "tracking";
    private bool sortAscending = true;
    private string? statusMessage;
    private bool isError;

    private IEnumerable<ShipmentDto> FilteredShipments
    {
        get
        {
            if (shipments is null) return [];

            var filtered = shipments.AsEnumerable();

            if (!string.IsNullOrWhiteSpace(filterText))
            {
                var filter = filterText.ToLowerInvariant();
                filtered = filtered.Where(s =>
                    s.TrackingNumber.Contains(filter, StringComparison.OrdinalIgnoreCase) ||
                    s.Destination.Contains(filter, StringComparison.OrdinalIgnoreCase) ||
                    s.Status.ToString().Contains(filter, StringComparison.OrdinalIgnoreCase));
            }

            filtered = sortColumn switch
            {
                "destination" => sortAscending ? filtered.OrderBy(s => s.Destination) : filtered.OrderByDescending(s => s.Destination),
                "status" => sortAscending ? filtered.OrderBy(s => s.Status) : filtered.OrderByDescending(s => s.Status),
                _ => sortAscending ? filtered.OrderBy(s => s.TrackingNumber) : filtered.OrderByDescending(s => s.TrackingNumber)
            };

            return filtered;
        }
    }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments");
        }
        catch (Exception ex)
        {
            statusMessage = $"Error loading shipments: {ex.Message}";
            isError = true;
        }
    }

    private void SortBy(string column)
    {
        if (sortColumn == column)
            sortAscending = !sortAscending;
        else
        {
            sortColumn = column;
            sortAscending = true;
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is null) return;

        var newStatus = (ShipmentStatus)int.Parse(e.Value.ToString()!);
        var request = new UpdateShipmentStatusRequest
        {
            ShipmentId = shipment.Id,
            NewStatus = newStatus
        };

        try
        {
            var response = await Http.PutAsJsonAsync("api/shipments/status", request);
            if (response.IsSuccessStatusCode)
            {
                shipment.Status = newStatus;
                statusMessage = $"Updated {shipment.TrackingNumber} to {newStatus}";
                isError = false;
            }
            else
            {
                statusMessage = $"Failed to update status: {response.StatusCode}";
                isError = true;
            }
        }
        catch (Exception ex)
        {
            statusMessage = $"Error: {ex.Message}";
            isError = true;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize]
@inject HttpClient Http

<PageTitle>Track Shipment</PageTitle>

<h1>Track Your Shipment</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input type="text" class="form-control" placeholder="Enter tracking number (e.g., TRK-2026-001)"
                   @bind="trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="TrackShipment" disabled="@isLoading">
                @if (isLoading)
                {
                    <span class="spinner-border spinner-border-sm" role="status"></span>
                }
                else
                {
                    <span>Track</span>
                }
            </button>
        </div>
    </div>
</div>

@if (trackedShipment is not null)
{
    <div class="card">
        <div class="card-header">
            <h5 class="mb-0">Shipment @trackedShipment.TrackingNumber</h5>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Status</dt>
                        <dd>
                            <span class="badge @GetStatusBadgeClass(trackedShipment.Status) fs-6">
                                @trackedShipment.Status
                            </span>
                        </dd>
                        <dt>Description</dt>
                        <dd>@trackedShipment.Description</dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>From</dt>
                        <dd>@trackedShipment.Origin</dd>
                        <dt>To</dt>
                        <dd>@trackedShipment.Destination</dd>
                        <dt>Shipped</dt>
                        <dd>@trackedShipment.ShippedDate.ToString("yyyy-MM-dd")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd class="fw-bold">@trackedShipment.EstimatedDelivery.ToString("yyyy-MM-dd")</dd>
                    </dl>
                </div>
            </div>

            <!-- Progress indicator -->
            <div class="mt-3">
                <h6>Shipment Progress</h6>
                <div class="progress" style="height: 30px;">
                    <div class="progress-bar @GetProgressBarClass(trackedShipment.Status)"
                         role="progressbar"
                         style="width: @(GetProgressPercent(trackedShipment.Status))%"
                         aria-valuenow="@GetProgressPercent(trackedShipment.Status)"
                         aria-valuemin="0" aria-valuemax="100">
                        @trackedShipment.Status
                    </div>
                </div>
            </div>
        </div>
    </div>
}

<hr class="my-4" />

<h3>My Shipments</h3>

@if (myShipments is null)
{
    <p><em>Loading your shipments...</em></p>
}
else if (!myShipments.Any())
{
    <p>You have no shipments associated with your account.</p>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped">
            <thead>
                <tr>
                    <th>Tracking #</th>
                    <th>Destination</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in myShipments)
                {
                    <tr>
                        <td>@shipment.TrackingNumber</td>
                        <td>@shipment.Destination</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                        </td>
                        <td>@shipment.EstimatedDelivery.ToString("yyyy-MM-dd")</td>
                        <td>
                            <button class="btn btn-sm btn-outline-primary"
                                    @onclick="() => QuickTrack(shipment.TrackingNumber)">
                                Details
                            </button>
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger mt-3">@errorMessage</div>
}

@code {
    private string trackingNumber = string.Empty;
    private ShipmentDto? trackedShipment;
    private List<ShipmentDto>? myShipments;
    private bool isLoading;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            myShipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments/my");
        }
        catch
        {
            myShipments = [];
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await TrackShipment();
    }

    private async Task TrackShipment()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        isLoading = true;
        errorMessage = null;
        trackedShipment = null;

        try
        {
            var response = await Http.GetAsync($"api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                trackedShipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
            }
            else if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            {
                errorMessage = $"No shipment found with tracking number '{trackingNumber}'.";
            }
            else
            {
                errorMessage = $"Error looking up shipment: {response.StatusCode}";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task QuickTrack(string tracking)
    {
        trackingNumber = tracking;
        await TrackShipment();
    }

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 30,
        ShipmentStatus.InTransit => 55,
        ShipmentStatus.OutForDelivery => 80,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 55,
        _ => 0
    };

    private static string GetProgressBarClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-primary"
    };

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };
}

